const root = $input.first().json || {};
const config = $('Prepare API and Research Fields').first().json || {};
const maxVideos = Math.max(1, Number(config.maxVideos || 1));
const seen = new Set();
const candidates = [];

function getApiResponse(value) {
  if (Array.isArray(value)) return value[0] || {};
  return value || {};
}

function extractClientCacheKey(url) {
  if (!url) return '';
  const text = String(url);
  const match = text.match(/[?&]clientCacheKey=([^&]+)/i);
  if (!match) return '';
  return decodeURIComponent(match[1])
    .replace(/\.(jpg|jpeg|png|webp|mp4)$/i, '')
    .trim();
}

function pushCandidate(videoId, source, item) {
  if (!videoId || seen.has(videoId)) return;
  seen.add(videoId);
  candidates.push({
    videoId,
    videoIdSource: source,
    searchItem: item || null
  });
}

function urlsFromList(list) {
  if (!Array.isArray(list)) return [];
  return list.map(entry => {
    if (typeof entry === 'string') return entry;
    if (entry && typeof entry === 'object') return entry.url || '';
    return '';
  }).filter(Boolean);
}

const response = getApiResponse(root);
const data = response.data || {};
const feeds = Array.isArray(data.feeds) ? data.feeds : [];

for (const feed of feeds) {
  const candidateUrls = [
    feed.main_url,
    feed.thumbnail_url,
    ...urlsFromList(feed.cover_thumbnail_urls),
    ...urlsFromList(feed.thumbnail_urls)
  ].filter(Boolean);

  for (const url of candidateUrls) {
    const videoId = extractClientCacheKey(url);
    if (videoId) {
      pushCandidate(videoId, 'data.feeds[].main_url/cover clientCacheKey', feed);
      break;
    }
  }

  if (candidates.length >= maxVideos) break;
}

const selected = candidates.slice(0, maxVideos);

if (selected.length === 0) {
  return [
    {
      json: {
        error: 'No detail videoId was extracted from data.feeds[].main_url or cover URL clientCacheKey fields in the search response.',
        baseUrl: config.baseUrl,
        token: config.token,
        keyword: config.keyword,
        page: config.page,
        maxVideos,
        rawSearchResponse: root
      }
    }
  ];
}

return selected.map(candidate => ({
  json: {
    baseUrl: config.baseUrl,
    token: config.token,
    keyword: config.keyword,
    page: config.page,
    maxVideos,
    videoId: candidate.videoId,
    videoIdSource: candidate.videoIdSource,
    searchItem: candidate.searchItem,
    rawSearchResponse: root
  }
}));

const rows = $input.all();
const extractedRows = $('Extract Video IDs with Code').all();
const config = $('Prepare API and Research Fields').first().json || {};

function firstArray(...values) {
  for (const value of values) {
    if (Array.isArray(value) && value.length > 0) return value;
  }
  return [];
}

function firstUrl(list) {
  if (!Array.isArray(list) || list.length === 0) return '';
  const first = list[0];
  if (typeof first === 'string') return first;
  if (first && typeof first === 'object') return first.url || '';
  return '';
}

function getApiResponse(value) {
  if (Array.isArray(value)) return value[0] || {};
  return value || {};
}

function getRepresentations(photo) {
  const adaptationSet = photo?.streamManifest?.adaptationSet || [];
  const representations = [];
  for (const set of adaptationSet) {
    for (const rep of (set.representation || [])) {
      representations.push(rep);
    }
  }
  return representations;
}

function normalizeSearchItem(searchItem) {
  if (!searchItem || typeof searchItem !== 'object') return {};
  return {
    caption: searchItem.caption || '',
    authorName: searchItem.user_name || '',
    authorId: searchItem.user_id ?? '',
    kwaiId: searchItem.kwaiId || '',
    publishTime: searchItem.time || '',
    timestamp: searchItem.timestamp ?? '',
    photoId: searchItem.photo_id ?? '',
    likeCount: searchItem.like_count ?? '',
    commentCount: searchItem.comment_count ?? '',
    shareCount: searchItem.share_count ?? '',
    viewCount: searchItem.view_count ?? '',
    durationMs: searchItem.duration ?? '',
    coverUrl: searchItem.main_url || searchItem.thumbnail_url || firstUrl(searchItem.cover_thumbnail_urls) || firstUrl(searchItem.thumbnail_urls),
    previewVideoUrl: searchItem.main_mv_url || firstUrl(searchItem.main_mv_urls),
    width: searchItem.ext_params?.w ?? '',
    height: searchItem.ext_params?.h ?? ''
  };
}

function normalizeDetailPhoto(photo) {
  if (!photo || typeof photo !== 'object') return {};
  const representations = getRepresentations(photo);
  const firstRep = representations[0] || {};
  return {
    caption: photo.caption || '',
    authorName: photo.user_name || '',
    authorId: photo.user_id ?? '',
    kwaiId: photo.kwaiId || '',
    publishTime: photo.time || '',
    timestamp: photo.timestamp ?? '',
    photoId: photo.photo_id ?? '',
    likeCount: photo.like_count ?? '',
    commentCount: photo.comment_count ?? '',
    shareCount: photo.share_count ?? '',
    viewCount: photo.view_count ?? '',
    collectCount: photo.collect_count ?? '',
    durationMs: photo.duration ?? '',
    coverUrl: photo.main_url || photo.thumbnail_url || firstUrl(photo.cover_thumbnail_urls) || firstUrl(photo.thumbnail_urls),
    videoUrl: firstRep.url || photo.main_mv_url || firstUrl(photo.main_mv_urls),
    backupVideoUrls: firstArray(firstRep.backupUrl),
    streamVideoId: photo.streamManifest?.videoId || '',
    mediaWidth: firstRep.width ?? photo.ext_params?.w ?? '',
    mediaHeight: firstRep.height ?? photo.ext_params?.h ?? '',
    qualityLabel: firstRep.qualityLabel || '',
    qualityType: firstRep.qualityType || ''
  };
}

return rows.map((item, index) => {
  const detailResponse = item.json || {};
  const extracted = extractedRows[index]?.json || extractedRows[0]?.json || {};
  const detailApiResponse = getApiResponse(detailResponse);
  const detailData = detailApiResponse.data || {};
  const photos = Array.isArray(detailData.photos) ? detailData.photos : [];
  const detailPhoto = photos[0] || {};
  const searchItem = extracted.searchItem || {};

  return {
    json: {
      requestedKeyword: config.keyword || extracted.keyword || '',
      page: extracted.page ?? config.page ?? '',
      videoId: extracted.videoId || '',
      videoIdSource: extracted.videoIdSource || '',
      searchVideo: normalizeSearchItem(searchItem),
      detailVideo: normalizeDetailPhoto(detailPhoto),
      debug: {
        searchResultCount: Array.isArray(getApiResponse(extracted.rawSearchResponse).data?.feeds) ? getApiResponse(extracted.rawSearchResponse).data.feeds.length : 0,
        detailPhotoCount: photos.length,
        detailResult: detailData.result ?? '',
        detailApiCode: detailApiResponse.code ?? '',
        detailApiMessage: detailApiResponse.message ?? ''
      },
      raw: {
        selectedSearchItem: searchItem,
        searchResponse: extracted.rawSearchResponse || null,
        detailPhoto,
        detailResponse
      }
    }
  };
});
